Here are the public test cases for feature1_model_feed_mapping:
{
  "description": "The model feed converts a successful upstream list into domain model rows and forwards upstream failures as a normalized error.",
  "cases": [
    {
      "input": {
        "upstream": "success",
        "payload": [
          {
            "id": 1
          }
        ]
      },
      "expected_output": "result=models\ncount=1\nitem[0].id=1\n"
    }
  ]
}

Here are the public test cases for feature3_launch_preference_storage:
{
  "description": "Launch preference storage returns the saved first-launch flag, falls back to true on read I/O failure, propagates unexpected read failures, and persists updates.",
  "cases": [
    {
      "input": {
        "stored_value": false
      },
      "expected_output": "first_time_launch=false\n"
    },
    {
      "input": {
        "failure": "io_on_read"
      },
      "expected_output": "first_time_launch=true\n"
    }
  ]
}

Here are the public test cases for feature6_home_state_coordinator:
{
  "description": "The home state coordinator exposes a Home screen title, loaded item identifiers, loading transitions, first-launch acknowledgement, generic error toast, and route navigation from a selected model.",
  "cases": [
    {
      "input": {
        "scenario": "show_loaded_home",
        "model_feed_status": "success",
        "model_feed": [
          {
            "id": 1
          },
          {
            "id": 2
          },
          {
            "id": 3
          }
        ],
        "first_time_launch": false
      },
      "expected_output": "screen_title=Home\nloading_sequence=false,true,false\nvisible_model_ids=1,2,3\nfirst_time_launch=false\ntoast=none\n"
    },
    {
      "input": {
        "scenario": "navigate_from_model",
        "model_feed_status": "success",
        "model_feed": [
          {
            "id": 1
          },
          {
            "id": 2
          },
          {
            "id": 3
          }
        ],
        "first_time_launch": false
      },
      "expected_output": "navigation_route=second/1\n"
    }
  ]
}
